    <script>
      window.__targetBoundsCalls = 0;
      const originalGetBoundingClientRect = Element.prototype.getBoundingClientRect;
      Element.prototype.getBoundingClientRect = function () {
        const bounds = originalGetBoundingClientRect.call(this);
        if (this.id !== 'target') return bounds;

        window.__targetBoundsCalls += 1;
        const offset = window.__targetBoundsCalls === 1 ? 24 : 0;

        return {
          ...bounds,
          bottom: bounds.bottom,
          height: bounds.height,
          left: bounds.left + offset,
          right: bounds.right + offset,
          top: bounds.top,
          width: bounds.width,
